import sys
import threading
from collections import deque

def main():
    import sys
    sys.setrecursionlimit(1 << 25)
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Precompute cells with magnets
    magnets = set()
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                magnets.add((i, j))

    # Directions: up, down, left, right
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # Check if a cell is blocked (has a magnet in adjacent cells)
    def is_blocked(i, j):
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < H and 0 <= nj < W:
                if (ni, nj) in magnets:
                    return True
        return False

    # BFS to find the size of the connected component
    def bfs(start_i, start_j):
        visited = set()
        queue = deque()
        queue.append((start_i, start_j))
        visited.add((start_i, start_j))
        count = 0

        while queue:
            i, j = queue.popleft()
            count += 1
            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < H and 0 <= nj < W:
                    if (ni, nj) not in magnets and (ni, nj) not in visited and not is_blocked(ni, nj):
                        visited.add((ni, nj))
                        queue.append((ni, nj))
        return count

    max_freedom = 0
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                max_freedom = max(max_freedom, bfs(i, j))
    print(max_freedom)

threading.Thread(target=main).start()
